function solve(nums: number[]): boolean {
    const n = nums.length;
    for (let p = 1; p < n - 1; p++) {
        // Check if first part is strictly increasing
        let validFirst = true;
        for (let i = 0; i < p; i++) {
            if (nums[i] >= nums[i + 1]) {
                validFirst = false;
                break;
            }
        }
        if (!validFirst) continue;
        // Find q
        let q = p;
        while (q + 1 < n && nums[q + 1] < nums[q]) {
            q++;
        }
        // Check if q is at least p + 1
        if (q <= p) {
            continue;
        }
        // Check if the last part is strictly increasing
        let validLast = true;
        for (let i = q; i < n - 1; i++) {
            if (nums[i] >= nums[i + 1]) {
                validLast = false;
                break;
            }
        }
        if (validLast) {
            return true;
        }
    }
    return false;
}

