function solve(nums: number[]): boolean {
    const n = nums.length;
    for (let p = 1; p < n - 1; p++) {
        // Check if first part is strictly increasing
        let validFirst = true;
        for (let i = 0; i < p; i++) {
            if (nums[i] >= nums[i + 1]) {
                validFirst = false;
                break;
            }
        }
        if (!validFirst) continue;
        // Find q
        let q = p;
        while (q + 1 < n && nums[q + 1] < nums[q]) {
            q++;
