        // Check if the last part is strictly increasing
        let validLast = true;
        for (let i = q; i < n - 1; i++) {
            if (nums[i] >= nums[i + 1]) {
                validLast = false;
                break;
            }
        }
        if (validLast) {
            return true;
        }
    }
    return false;
}

